import{_ as a,o as t,c as l,E as o}from"./chunks/framework.BRIYLu4C.js";const u=JSON.parse('{"title":"CPP 入门教程 Part 2","description":"","frontmatter":{"title":"CPP 入门教程 Part 2","date":"2024-10-29T17:14:34.000Z","excerpt":"","tags":[],"categories":["C++"]},"headers":[],"relativePath":"posts/CPP-入门教程-Part-2.md","filePath":"posts/CPP-入门教程-Part-2.md","lastUpdated":null}'),e={name:"posts/CPP-入门教程-Part-2.md"};function n(p,s,c,d,r,i){return t(),l("div",null,[...s[0]||(s[0]=[o(`<h2 id="c-程序结构" tabindex="-1">C++ 程序结构 <a class="header-anchor" href="#c-程序结构" aria-label="Permalink to &quot;C++ 程序结构&quot;">​</a></h2><p>我们分析一下上一章的 Hello World 程序。</p><div class="language-cpp"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki github-light vp-code" tabindex="0"><code><span class="line"><span style="color:#D73A49;">#include</span><span style="color:#032F62;"> &lt;iostream&gt;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D73A49;">int</span><span style="color:#6F42C1;"> main</span><span style="color:#24292E;">() {</span></span>
<span class="line"><span style="color:#6F42C1;">    std</span><span style="color:#24292E;">::cout </span><span style="color:#D73A49;">&lt;&lt;</span><span style="color:#032F62;"> &quot;Hello, World!&quot;</span><span style="color:#D73A49;"> &lt;&lt;</span><span style="color:#6F42C1;"> std</span><span style="color:#24292E;">::endl;</span></span>
<span class="line"><span style="color:#D73A49;">    return</span><span style="color:#005CC5;"> 0</span><span style="color:#24292E;">;</span></span>
<span class="line"><span style="color:#24292E;">}</span></span></code></pre></div><p><code>#include &lt;iostream&gt;</code>: 这是一个预处理指令，用于包含标准输入输出流库<code>&lt;iostream&gt;</code>，允许我们使用<code>std::cout</code>来输出数据。</p><p><code>int main() { ... }</code>: 这是主函数<code>main</code>，程序从这里开始执行。</p><p><code>std::cout &lt;&lt; &quot;Hello, World!&quot; &lt;&lt; std::endl;</code>: 这行代码使用标准输出流<code>std::cout</code>来打印字符串&quot;Hello, World!&quot;，<code>std::endl</code>用于在输出后换行。</p><p><code>return 0;</code>: 表示程序成功结束，并返回值 0 给操作系统。</p><h2 id="编译-执行-c-程序" tabindex="-1">编译 &amp; 执行 C++ 程序 <a class="header-anchor" href="#编译-执行-c-程序" aria-label="Permalink to &quot;编译 &amp; 执行 C++ 程序&quot;">​</a></h2><p>C++ 程序代码编写完成后，需要编译才能执行。</p><h3 id="编译" tabindex="-1">编译 <a class="header-anchor" href="#编译" aria-label="Permalink to &quot;编译&quot;">​</a></h3><p>使用一个 C++ 编译器（如 g++）来将源代码转换为可执行程序。 在命令行输入以下命令以编译上一章的 Hello World 程序：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki github-light vp-code" tabindex="0"><code><span class="line"><span style="color:#6F42C1;">g++</span><span style="color:#005CC5;"> -o</span><span style="color:#032F62;"> hello</span><span style="color:#032F62;"> hello.cpp</span></span></code></pre></div><ul><li><code>g++</code>: 调用 GNU C++ 编译器。</li><li><code>-o hello</code>: 指定输出文件名为 <code>hello</code>。<code>-o</code> 是 <code>g++</code> 命令的参数，用于指定输出的文件名。</li><li><code>hello.cpp</code>: 源代码文件名。</li></ul><h3 id="执行" tabindex="-1">执行 <a class="header-anchor" href="#执行" aria-label="Permalink to &quot;执行&quot;">​</a></h3><p>编译成功后，生成的可执行文件可以通过在终端输入以下命令运行：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki github-light vp-code" tabindex="0"><code><span class="line"><span style="color:#6F42C1;">./hello</span></span></code></pre></div><p>这将会在终端上打印出 &quot;Hello, World!&quot;。</p><h2 id="c-基本语法" tabindex="-1">C++ 基本语法 <a class="header-anchor" href="#c-基本语法" aria-label="Permalink to &quot;C++ 基本语法&quot;">​</a></h2><h3 id="面向对象编程-oop" tabindex="-1">面向对象编程 (OOP) <a class="header-anchor" href="#面向对象编程-oop" aria-label="Permalink to &quot;面向对象编程 (OOP)&quot;">​</a></h3><p>C++ 程序可以定义为对象的集合，这些对象通过调用彼此的方法进行交互。现在让我们简要地看一下什么是类、对象，方法、即时变量。</p><ul><li><p>对象 - 对象具有状态和行为。例如：一只狗的状态 - 颜色、名称、品种，行为 - 摇动、叫唤、吃。对象是类的实例。</p></li><li><p>类 - 类可以定义为描述对象行为/状态的模板/蓝图。</p></li><li><p>方法 - 从基本上说，一个方法表示一种行为。一个类可以包含多个方法。可以在方法中写入逻辑、操作数据以及执行所有的动作。</p></li><li><p>成员变量 - 每个对象都有其自己成员变量。对象的状态是由这些成员变量的值构成的。</p></li></ul><h3 id="语句结束符" tabindex="-1">语句结束符 <a class="header-anchor" href="#语句结束符" aria-label="Permalink to &quot;语句结束符&quot;">​</a></h3><p>在 C++ 中，每个语句通常以分号 (<code>;</code>) 结束。这是必须的，因为分号告诉编译器该语句的结束。缺少分号会导致编译错误。</p><p>例如：</p><div class="language-cpp"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki github-light vp-code" tabindex="0"><code><span class="line"><span style="color:#D73A49;">int</span><span style="color:#24292E;"> a </span><span style="color:#D73A49;">=</span><span style="color:#005CC5;"> 5</span><span style="color:#24292E;">;</span></span>
<span class="line"><span style="color:#D73A49;">int</span><span style="color:#24292E;"> b </span><span style="color:#D73A49;">=</span><span style="color:#005CC5;"> 10</span><span style="color:#24292E;">;</span></span>
<span class="line"><span style="color:#D73A49;">int</span><span style="color:#24292E;"> sum </span><span style="color:#D73A49;">=</span><span style="color:#24292E;"> a </span><span style="color:#D73A49;">+</span><span style="color:#24292E;"> b;</span></span></code></pre></div><p>每个变量定义和赋值语句都以分号结尾。</p><blockquote><p>早期的编译器设计较为简单，需要明确的标识符来区分语句，而分号就是这样一个清晰的标识符。随着编译器技术的发展，虽然可以设计更智能的解析方式，但 C++继承自 C 语言, 保留分号可以保持向后兼容性。</p></blockquote><h3 id="代码块" tabindex="-1">代码块 <a class="header-anchor" href="#代码块" aria-label="Permalink to &quot;代码块&quot;">​</a></h3><p>代码块是用花括号 <code>{}</code> 括起来的一系列语句。代码块用于将多个语句组合为一个单元，通常用于函数、条件和循环中。</p><p>示例：</p><div class="language-cpp"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki github-light vp-code" tabindex="0"><code><span class="line"><span style="color:#D73A49;">if</span><span style="color:#24292E;"> (a </span><span style="color:#D73A49;">&lt;</span><span style="color:#24292E;"> b) {</span></span>
<span class="line"><span style="color:#6F42C1;">    std</span><span style="color:#24292E;">::cout </span><span style="color:#D73A49;">&lt;&lt;</span><span style="color:#032F62;"> &quot;a is less than b.&quot;</span><span style="color:#D73A49;"> &lt;&lt;</span><span style="color:#6F42C1;"> std</span><span style="color:#24292E;">::endl;</span></span>
<span class="line"><span style="color:#24292E;">} </span><span style="color:#D73A49;">else</span><span style="color:#24292E;"> {</span></span>
<span class="line"><span style="color:#6F42C1;">    std</span><span style="color:#24292E;">::cout </span><span style="color:#D73A49;">&lt;&lt;</span><span style="color:#032F62;"> &quot;a is not less than b.&quot;</span><span style="color:#D73A49;"> &lt;&lt;</span><span style="color:#6F42C1;"> std</span><span style="color:#24292E;">::endl;</span></span>
<span class="line"><span style="color:#24292E;">}</span></span></code></pre></div><p>在上面的代码中，<code>if</code> 和 <code>else</code> 都包含各自的代码块。</p><p>函数定义也是代码块的一个例子：</p><div class="language-cpp"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki github-light vp-code" tabindex="0"><code><span class="line"><span style="color:#D73A49;">int</span><span style="color:#6F42C1;"> add</span><span style="color:#24292E;">(</span><span style="color:#D73A49;">int</span><span style="color:#E36209;"> x</span><span style="color:#24292E;">, </span><span style="color:#D73A49;">int</span><span style="color:#E36209;"> y</span><span style="color:#24292E;">) {</span></span>
<span class="line"><span style="color:#D73A49;">    return</span><span style="color:#24292E;"> x </span><span style="color:#D73A49;">+</span><span style="color:#24292E;"> y;</span></span>
<span class="line"><span style="color:#24292E;">}</span></span></code></pre></div><p>这里，<code>add</code> 函数的主体是一个代码块，由花括号括起来。</p><p>通过使用分号和代码块，C++ 能够明确地分隔逻辑单元，从而支持复杂的逻辑。</p><h3 id="标识符" tabindex="-1">标识符 <a class="header-anchor" href="#标识符" aria-label="Permalink to &quot;标识符&quot;">​</a></h3><p>标识符是用于标识变量、函数、类等实体的名称。它可以由字母（大写或小写）、数字和下划线组成，但不能以数字开头。例如：</p><div class="language-cpp"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki github-light vp-code" tabindex="0"><code><span class="line"><span style="color:#D73A49;">int</span><span style="color:#24292E;"> myVariable;</span></span>
<span class="line"><span style="color:#D73A49;">float</span><span style="color:#24292E;"> _value;</span></span>
<span class="line"><span style="color:#D73A49;">char</span><span style="color:#24292E;"> letter1;</span></span></code></pre></div><ul><li>合法标识符示例：<code>myVariable</code>, <code>value123</code>, <code>_temp</code></li><li>非法标识符示例：<code>1stValue</code>（不能以数字开头）</li></ul><p>在 C++ 中，标识符区分大小写，因此 <code>MyVariable</code> 和 <code>myvariable</code> 是两个不同的标识符。</p><p>选择标识符时应使用有意义的名称，以便代码易于阅读和维护。</p><h3 id="关键字" tabindex="-1">关键字 <a class="header-anchor" href="#关键字" aria-label="Permalink to &quot;关键字&quot;">​</a></h3><p>下表列出了 C++ 中的保留字。这些保留字不能作为常量名、变量名或其他标识符名称。</p><table tabindex="0"><thead><tr><th>关键字</th><th></th><th></th><th></th></tr></thead><tbody><tr><td>asm</td><td>else</td><td>new</td><td>this</td></tr><tr><td>auto</td><td>enum</td><td>operator</td><td>throw</td></tr><tr><td>bool</td><td>explicit</td><td>private</td><td>true</td></tr><tr><td>break</td><td>export</td><td>protected</td><td>try</td></tr><tr><td>case</td><td>extern</td><td>public</td><td>typedef</td></tr><tr><td>catch</td><td>false</td><td>register</td><td>typeid</td></tr><tr><td>char</td><td>float</td><td>reinterpret_cast</td><td>typename</td></tr><tr><td>class</td><td>for</td><td>return</td><td>union</td></tr><tr><td>const</td><td>friend</td><td>short</td><td>unsigned</td></tr><tr><td>const_cast</td><td>goto</td><td>signed</td><td>using</td></tr><tr><td>continue</td><td>if</td><td>sizeof</td><td>virtual</td></tr><tr><td>default</td><td>inline</td><td>static</td><td>void</td></tr><tr><td>delete</td><td>int</td><td>static_cast</td><td>volatile</td></tr><tr><td>do</td><td>long</td><td>struct</td><td>wchar_t</td></tr><tr><td>double</td><td>mutable</td><td>switch</td><td>while</td></tr><tr><td>dynamic_cast</td><td>namespace</td><td>template</td><td></td></tr></tbody></table><h3 id="空格" tabindex="-1">空格 <a class="header-anchor" href="#空格" aria-label="Permalink to &quot;空格&quot;">​</a></h3><p>只包含空格的行，被称为空白行，可能带有注释，C++ 编译器会完全忽略它。</p><p>在 C++ 中，空格用于描述空白符、制表符、换行符和注释。空格分隔语句的各个部分，让编译器能识别语句中的某个元素（比如 int）在哪里结束，下一个元素在哪里开始。因此，在下面的语句中：</p><div class="language-cpp"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki github-light vp-code" tabindex="0"><code><span class="line"><span style="color:#D73A49;">int</span><span style="color:#24292E;"> age;</span></span></code></pre></div><p>在这里，int 和 age 之间必须至少有一个空格字符（通常是一个空白符），这样编译器才能够区分它们。另一方面，在下面的语句中：</p><div class="language-cpp"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki github-light vp-code" tabindex="0"><code><span class="line"><span style="color:#24292E;">fruit </span><span style="color:#D73A49;">=</span><span style="color:#24292E;"> apples </span><span style="color:#D73A49;">+</span><span style="color:#24292E;"> oranges;</span><span style="color:#6A737D;">   // 获取水果的总数</span></span></code></pre></div><p><code>fruit</code> 和<code>=</code>，或者<code>=</code> 和 <code>apples</code> 之间的空格字符不是必需的，但是为了增强可读性，您可以根据需要适当增加一些空格。</p><h3 id="注释" tabindex="-1">注释 <a class="header-anchor" href="#注释" aria-label="Permalink to &quot;注释&quot;">​</a></h3><p>程序的注释是解释性语句，您可以在 C++ 代码中包含注释，这将提高源代码的可读性。所有的编程语言都允许某种形式的注释。</p><p>C++ 支持单行注释和多行注释。注释中的所有字符会被 C++ 编译器忽略。</p><p>C++ 注释以 <code>/*</code> 开始，以 <code>*/</code> 终止。例如：</p><div class="language-cpp"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki github-light vp-code" tabindex="0"><code><span class="line"><span style="color:#6A737D;">/* 这是注释 */</span></span>
<span class="line"><span style="color:#6A737D;">/*</span></span>
<span class="line"><span style="color:#6A737D;"> * C++ 注释也可以跨行</span></span>
<span class="line"><span style="color:#6A737D;"> */</span></span></code></pre></div><p>注释也能以 <code>//</code> 开始，直到行末为止。例如：</p><div class="language-cpp"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki github-light vp-code" tabindex="0"><code><span class="line"><span style="color:#D73A49;">#include</span><span style="color:#032F62;"> &lt;iostream&gt;</span></span>
<span class="line"><span style="color:#D73A49;">int</span><span style="color:#6F42C1;"> main</span><span style="color:#24292E;">() {</span></span>
<span class="line"><span style="color:#24292E;">    cout </span><span style="color:#D73A49;">&lt;&lt;</span><span style="color:#032F62;"> &quot;Hello World&quot;</span><span style="color:#24292E;">;</span><span style="color:#6A737D;"> // 输出 Hello World</span></span>
<span class="line"><span style="color:#D73A49;">    return</span><span style="color:#005CC5;"> 0</span><span style="color:#24292E;">;</span></span>
<span class="line"><span style="color:#24292E;">}</span></span></code></pre></div><p>当上面的代码被编译时，编译器会忽略 <code>// 输出 Hello World</code>，最后会产生以下结果：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki github-light vp-code" tabindex="0"><code><span class="line"><span>Hello World</span></span></code></pre></div><p>在 <code>/*</code> 和 <code>*/</code> 注释内部，<code>//</code> 字符没有特殊的含义。在 <code>//</code> 注释内，<code>/*</code> 和 <code>*/</code> 字符也没有特殊的含义。因此，您可以在一种注释内嵌套另一种注释。例如：</p><div class="language-cpp"><button title="Copy Code" class="copy"></button><span class="lang">cpp</span><pre class="shiki github-light vp-code" tabindex="0"><code><span class="line"><span style="color:#6A737D;">/* 用于输出 Hello World 的注释</span></span>
<span class="line"><span style="color:#6A737D;">cout &lt;&lt; &quot;Hello World&quot;; // 输出 Hello World</span></span>
<span class="line"><span style="color:#6A737D;">*/</span></span></code></pre></div><h2 id="注" tabindex="-1">注 <a class="header-anchor" href="#注" aria-label="Permalink to &quot;注&quot;">​</a></h2><p>无</p><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><p>无</p>`,67)])])}const h=a(e,[["render",n]]);export{u as __pageData,h as default};
